+	}
+
+	for _, d := range deps {
+		depType := string(d.DependencyType)
+		if !blockingDepTypes[depType] {
+			continue
+		}
+		status := string(d.Status)
+		if status != "closed" && status != "tombstone" {
+			return true
+		}
+	}
+	return false
